# PowerShell script to jiggle the mouse cursor 1 pixel every 60 seconds for 5 minutes
# This simulates minimal activity to avoid idle detection.
# Run this in PowerShell as Administrator if needed for mouse control.
# WARNING: Use at your own risk; this may violate company policies.

Add-Type @"
using System;
using System.Runtime.InteropServices;
public class Mouse {
    [DllImport("user32.dll")]
    public static extern bool GetCursorPos(out Point lpPoint);
    [DllImport("user32.dll")]
    public static extern bool SetCursorPos(int x, int y);
    public struct Point {
        public int X;
        public int Y;
    }
}
"@

function Get-CursorPosition {
    $point = New-Object Mouse+Point
    [Mouse]::GetCursorPos([ref]$point) | Out-Null
    return $point
}

function Set-CursorPosition {
    param($x, $y)
    [Mouse]::SetCursorPos($x, $y) | Out-Null
}

# Run for 5 minutes (5 jiggles, every 60 seconds)
$endTime = (Get-Date).AddMinutes(5)
Write-Host "Starting mouse jiggle for 5 minutes. Press Ctrl+C to stop early."
while ((Get-Date) -lt $endTime) {
    $pos = Get-CursorPosition
    # Jiggle: Move 1 pixel right, wait briefly, move back
    Set-CursorPosition ($pos.X + 1) $pos.Y
    Start-Sleep -Milliseconds 50
    Set-CursorPosition $pos.X $pos.Y
    Write-Host "Jiggled mouse at $(Get-Date -Format 'HH:mm:ss')"

    # Wait 60 seconds before next jiggle
    Start-Sleep -Seconds 60
}

Write-Host "5 minutes complete. Script ending."
